// src/components/FormAluno.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const { user } = useAuth();
  const token = user.token;
  const headers = { Authorization: `Bearer ${token}` };
  const alunoId = alunoEditando?.id;

  // Campos de texto existentes
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [periodoId, setPeriodoId] = useState('');
  const [mensagem, setMensagem] = useState('');

  // Novos campos:
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [role, setRole] = useState('aluno'); // valor padrĂŁo = "aluno"

  // Lista de perĂ­odos
  const [periodos, setPeriodos] = useState([]);

  // Boxes do aluno
  const [boxes, setBoxes] = useState([]);
  const [novoConteudo, setNovoConteudo] = useState('');

  // Carrega perĂ­odos uma vez
  useEffect(() => {
    axios.get('/api/periodos', { headers })
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  }, [headers]);

  // Carrega boxes sempre que trocar de alunoEditando
  useEffect(() => {
    if (!alunoId) {
      setBoxes([]);
      return;
    }
    axios.get(`/api/boxes/${alunoId}`, { headers })
      .then(res => setBoxes(res.data))
      .catch(err => console.error('Erro ao carregar boxes:', err));
  }, [alunoId, headers]);

  // Preenche campos quando editar
  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome || '');
      setRa(alunoEditando.ra || '');
      setPeriodoId(String(alunoEditando.periodo_id ?? ''));
      setUsuario(alunoEditando.usuario || '');
      setRole(alunoEditando.role || 'aluno');
      setSenha(''); 
    } else {
      setNome(''); setRa(''); setPeriodoId('');
      setUsuario(''); setSenha(''); setRole('aluno');
      setBoxes([]); setNovoConteudo('');
    }
    setMensagem('');
  }, [alunoEditando]);

  // Cria um box
  function handleCriarBox() {
    if (!novoConteudo.trim() || !alunoId) return;
    axios.post('/api/boxes', {
      aluno_id: alunoId,
      conteudo: novoConteudo.trim()
    }, { headers })
      .then(res => {
        setBoxes(prev => [res.data, ...prev]);
        setNovoConteudo('');
      })
      .catch(err => console.error(err));
  }

  // Deleta um box
  function handleDeletarBox(id) {
    axios.delete(`/api/boxes/${id}`, { headers })
      .then(() => {
        setBoxes(prev => prev.filter(b => b.id !== id));
      })
      .catch(err => console.error(err));
  }

  // ValidaĂ§Ăµes
  function validarNomeCompleto(n) {
    const partes = n.trim().split(' ').filter(p => p.length >= 2);
    return partes.length >= 2;
  }
  function validarRA(r) {
    return /^\d{1,9}$/.test(r);
  }

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!validarNomeCompleto(nome)) {
      setMensagem('Informe o nome completo!');
      return;
    }
    if (!validarRA(ra)) {
      setMensagem('O RA deve conter apenas nĂşmeros e atĂ© 9 dĂ­gitos!');
      return;
    }
    if (!usuario.trim()) {
      setMensagem('Insira um usuĂˇrio para login!');
      return;
    }
    if (!alunoEditando && senha.length < 4) {
      setMensagem('Senha deve ter no mĂ­nimo 4 caracteres!');
      return;
    }
    if (!periodoId) {
      setMensagem('Selecione um perĂ­odo!');
      return;
    }

    const dados = {
      nome,
      ra,
      periodo_id: periodoId,
      usuario,
      role
    };
    if (!alunoEditando) dados.senha = senha;
    else if (senha) dados.senha = senha;

    const request = alunoEditando
      ? axios.put(`/api/alunos/${alunoId}`, dados, { headers })
      : axios.post('/api/alunos', dados, { headers });

    request
      .then(() => {
        setMensagem(alunoEditando
          ? 'Aluno atualizado com sucesso!'
          : 'Aluno cadastrado com sucesso!'
        );
        setNome(''); setRa(''); setPeriodoId('');
        setUsuario(''); setSenha(''); setRole('aluno');
        onNovoAluno();
        if (alunoEditando) onFimEdicao();
      })
      .catch(err => {
        const errMsg = err.response?.data?.error;
        setMensagem(errMsg || (alunoEditando 
          ? 'Erro ao atualizar aluno.' 
          : 'Erro ao cadastrar aluno.'));
      });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <h2 className="text-xl font-bold">
        {alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}
      </h2>

      {/* ... campos existentes (Nome, RA, PerĂ­odo, UsuĂˇrio, Senha, Role) ... */}

      <div className="box-container">
        <h3 className="font-semibold">Boxes do Aluno</h3>
        {alunoId && boxes.map(b => (
          <div key={b.id} className="box-item flex justify-between items-center p-2 border rounded mb-2">
            <span>{b.conteudo}</span>
            <button type="button" onClick={() => handleDeletarBox(b.id)}>Ă—</button>
          </div>
        ))}
        {alunoId && (
          <div className="flex gap-2">
            <input
              className="flex-1 border rounded px-2 py-1"
              value={novoConteudo}
              onChange={e => setNovoConteudo(e.target.value)}
              placeholder="ConteĂşdo do box"
            />
            <button
              type="button"
              onClick={handleCriarBox}
              className="bg-blue-600 text-white px-4 py-1 rounded"
            >
              Adicionar
            </button>
          </div>
        )}
      </div>

      {/* BotĂµes de submissĂŁo */}
      <div className="flex items-center gap-4 mt-4">
        <button
          type="submit"
          className="bg-[#1A1C2C] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#3B4854]"
        >
          {alunoEditando ? 'Atualizar' : 'Cadastrar'}
        </button>
        {alunoEditando && (
          <button
            type="button"
            className="bg-[#DA3648] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#BC3140]"
            onClick={onFimEdicao}
          >
            Cancelar
          </button>
        )}
      </div>

      {mensagem && (
        <p className={`mt-2 ${mensagem.toLowerCase().includes('sucesso') ? 'text-green-600' : 'text-red-600'}`}>
          {mensagem}
        </p>
      )}
    </form>
  );
}

export default FormAluno;
